-- 1. Setup the custom Medicine Category ENUM
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'medicinecategory') THEN
        CREATE TYPE medicinecategory AS ENUM (
            'GENERAL', 'OTC', 'SCHEDULE_H', 'SCHEDULE_H1', 'SCHEDULE_X'
        );
    END IF;
END $$;

-- 2. Create the Medicines Table
CREATE TABLE IF NOT EXISTS medicines (
    id SERIAL PRIMARY KEY,
    product_name CHARACTER VARYING NOT NULL,
    generic_name CHARACTER VARYING,
    description CHARACTER VARYING,
    unit_price DOUBLE PRECISION,
    manufacturer_id INTEGER REFERENCES manufacturers(id),
    hsn_code CHARACTER VARYING(8),
    category medicinecategory,
    uom CHARACTER VARYING,
    storage_type CHARACTER VARYING,
    is_active BOOLEAN,
    selling_price_percent DOUBLE PRECISION
);

